package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.ObjectInputStream;
import java.io.ObjectStreamClass;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;

class UnsafeAllocatorTest {

  @Test
  void testCreate_withSunMiscUnsafe() throws Exception {
    // Setup real Class for sun.misc.Unsafe
    Class<?> unsafeClass = Class.forName("sun.misc.Unsafe");
    Field theUnsafeField = unsafeClass.getDeclaredField("theUnsafe");
    theUnsafeField.setAccessible(true);
    Object unsafeInstance = theUnsafeField.get(null);
    Method allocateInstanceMethod = unsafeClass.getMethod("allocateInstance", Class.class);

    try (MockedStatic<Class> mockedStatic = mockStatic(Class.class)) {
      mockedStatic.when(() -> Class.forName("sun.misc.Unsafe")).thenReturn(unsafeClass);

      // Spy on unsafeClass to mock getDeclaredField and getMethod
      // But since unsafeClass is real, we don't mock these methods, just let them call real methods

      UnsafeAllocator allocator = invokeCreate();

      class Dummy {}

      // Spy on allocateInstance.invoke to return new Dummy instance
      // But allocateInstanceMethod is real, so we cannot mock its invoke method directly
      // Instead, we rely on real behavior

      Dummy instance = allocator.newInstance(Dummy.class);
      assertNotNull(instance);
      assertEquals(Dummy.class, instance.getClass());
    }
  }

  @Test
  void testCreate_withObjectStreamClass() throws Exception {
    Method getConstructorIdMethod = ObjectStreamClass.class.getDeclaredMethod("getConstructorId", Class.class);
    Method newInstanceMethod = ObjectStreamClass.class.getDeclaredMethod("newInstance", Class.class, int.class);
    getConstructorIdMethod.setAccessible(true);
    newInstanceMethod.setAccessible(true);

    try (MockedStatic<Class> mockedStaticClass = mockStatic(Class.class)) {
      mockedStaticClass.when(() -> Class.forName("sun.misc.Unsafe")).thenThrow(ClassNotFoundException.class);

      try (MockedStatic<ObjectStreamClass> mockedStaticOSC = mockStatic(ObjectStreamClass.class)) {
        // Mock getDeclaredMethod calls on ObjectStreamClass
        mockedStaticOSC.when(() -> ObjectStreamClass.class.getDeclaredMethod("getConstructorId", Class.class))
            .thenReturn(getConstructorIdMethod);
        mockedStaticOSC.when(() -> ObjectStreamClass.class.getDeclaredMethod("newInstance", Class.class, int.class))
            .thenReturn(newInstanceMethod);

        UnsafeAllocator allocator = invokeCreate();

        class Dummy {}

        Dummy dummyInstance = new Dummy();

        // We cannot mock invoke on real Method, so use spy to intercept invoke calls
        Method spyGetConstructorIdMethod = spy(getConstructorIdMethod);
        Method spyNewInstanceMethod = spy(newInstanceMethod);

        // But since invoke is final, Mockito cannot mock it, so we rely on real methods

        Dummy instance = allocator.newInstance(Dummy.class);
        assertNotNull(instance);
        assertEquals(Dummy.class, instance.getClass());
      }
    }
  }

  @Test
  void testCreate_withObjectInputStream() throws Exception {
    Method newInstanceMethod = ObjectInputStream.class.getDeclaredMethod("newInstance", Class.class, Class.class);
    newInstanceMethod.setAccessible(true);

    try (MockedStatic<Class> mockedStaticClass = mockStatic(Class.class)) {
      mockedStaticClass.when(() -> Class.forName("sun.misc.Unsafe")).thenThrow(ClassNotFoundException.class);

      try (MockedStatic<ObjectStreamClass> mockedStaticOSC = mockStatic(ObjectStreamClass.class)) {
        mockedStaticOSC.when(() -> ObjectStreamClass.class.getDeclaredMethod("getConstructorId", Class.class))
            .thenThrow(NoSuchMethodException.class);

        try (MockedStatic<ObjectInputStream> mockedStaticOIS = mockStatic(ObjectInputStream.class)) {
          mockedStaticOIS.when(() -> ObjectInputStream.class.getDeclaredMethod("newInstance", Class.class, Class.class))
              .thenReturn(newInstanceMethod);

          UnsafeAllocator allocator = invokeCreate();

          class Dummy {}

          Dummy instance = allocator.newInstance(Dummy.class);
          assertNotNull(instance);
          assertEquals(Dummy.class, instance.getClass());
        }
      }
    }
  }

  @Test
  void testCreate_fallbackUnsupportedOperation() throws Exception {
    try (MockedStatic<Class> mockedStaticClass = mockStatic(Class.class)) {
      mockedStaticClass.when(() -> Class.forName("sun.misc.Unsafe")).thenThrow(ClassNotFoundException.class);

      try (MockedStatic<ObjectStreamClass> mockedStaticOSC = mockStatic(ObjectStreamClass.class)) {
        mockedStaticOSC.when(() -> ObjectStreamClass.class.getDeclaredMethod("getConstructorId", Class.class))
            .thenThrow(NoSuchMethodException.class);

        try (MockedStatic<ObjectInputStream> mockedStaticOIS = mockStatic(ObjectInputStream.class)) {
          mockedStaticOIS.when(() -> ObjectInputStream.class.getDeclaredMethod("newInstance", Class.class, Class.class))
              .thenThrow(NoSuchMethodException.class);

          UnsafeAllocator allocator = invokeCreate();

          class Dummy {}

          UnsupportedOperationException ex = assertThrows(UnsupportedOperationException.class,
              () -> allocator.newInstance(Dummy.class));
          assertTrue(ex.getMessage().contains("Cannot allocate"));
        }
      }
    }
  }

  // Utility method to invoke private static create() via reflection
  private UnsafeAllocator invokeCreate() throws Exception {
    Method createMethod = UnsafeAllocator.class.getDeclaredMethod("create");
    createMethod.setAccessible(true);
    return (UnsafeAllocator) createMethod.invoke(null);
  }
}
